import { expectDiagnosticEmpty, expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@product", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_product
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T004.T004_01
    it("Products.<Name> namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @product
        namespace Products.MyProduct;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T004.T004_02
    it("with @assumption attached", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @product
        @assumption(#{ id: "A01", assumption: "External API is available", source: "https://example.com" })
        namespace Products.MyProduct;
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T004.T004_03
    it("namespace not starting with Products.", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @product
        namespace MyProduct;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Products\./,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T004.T004_04
    it("bare top-level namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @product
        namespace ReviewBot;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T004.T004_05
    it("too many segments (Products.Foo.Bar)", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @product
        namespace Products.Foo.Bar;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
      });
    });
  });
});
